/**
 * marked.min.js - Minimal Markdown to HTML renderer
 * Supports: headers, bold, italic, code (inline/block), lists (ordered/unordered),
 * links, paragraphs, line breaks, blockquotes, images
 */
(function() {
  'use strict';

  function marked(src) {
    if (!src) return '';
    src = src.replace(/\r\n/g, '\n').replace(/\r/g, '\n');

    // Escape HTML
    src = src.replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;');

    // Code blocks (fenced) - must be before other processing
    var codeBlocks = [];
    src = src.replace(/```(\w*)\n([\s\S]*?)```/g, function(m, lang, code) {
      var idx = codeBlocks.length;
      codeBlocks.push('<pre><code' + (lang ? ' class="language-' + escapeHtml(lang) + '"' : '') + '>' + escapeHtml(code.trim()) + '</code></pre>');
      return '%%CODEBLOCK' + idx + '%%';
    });

    // Inline code
    src = src.replace(/`([^`]+)`/g, '<code>$1</code>');

    // Blockquotes
    src = src.replace(/^(>[\s\S]*?)(?=\n\n|\n(?!>)|$)/gm, function(m) {
      var lines = m.split('\n').map(function(l) { return l.replace(/^>\s?/, '').trim(); });
      return '<blockquote>' + lines.join('\n') + '</blockquote>';
    });

    // Headers (atx-style)
    src = src.replace(/^######\s+(.+)/gm, '<h6>$1</h6>');
    src = src.replace(/^#####\s+(.+)/gm, '<h5>$1</h5>');
    src = src.replace(/^####\s+(.+)/gm, '<h4>$1</h4>');
    src = src.replace(/^###\s+(.+)/gm, '<h3>$1</h3>');
    src = src.replace(/^##\s+(.+)/gm, '<h2>$1</h2>');
    src = src.replace(/^#\s+(.+)/gm, '<h1>$1</h1>');

    // Horizontal rules
    src = src.replace(/^(?:[-*_]){3,}\s*$/gm, '<hr>');

    // Unordered lists
    src = src.replace(/(?:^[*-]\s+.*(?:\n[*-]\s+.*)*)/gm, function(m) {
      var items = m.split('\n').map(function(l) { return '<li>' + l.replace(/^[*-]\s+/, '') + '</li>'; });
      return '<ul>' + items.join('') + '</ul>';
    });

    // Ordered lists
    src = src.replace(/(?:^\d+\.\s+.*(?:\n\d+\.\s+.*)*)/gm, function(m) {
      var items = m.split('\n').map(function(l) { return '<li>' + l.replace(/^\d+\.\s+/, '') + '</li>'; });
      return '<ol>' + items.join('') + '</ol>';
    });

    // Links [text](url)
    src = src.replace(/\[([^\]]+)\]\(([^)]+)\)/g, '<a href="$2" target="_blank" rel="noopener">$1</a>');

    // Images ![alt](url)
    src = src.replace(/!\[([^\]]*)\]\(([^)]+)\)/g, '<img src="$2" alt="$1" loading="lazy">');

    // Bold + Italic ***
    src = src.replace(/\*\*\*(.+?)\*\*\*/g, '<strong><em>$1</em></strong>');
    src = src.replace(/___(.+?)___/g, '<strong><em>$1</em></strong>');

    // Bold **
    src = src.replace(/\*\*(.+?)\*\*/g, '<strong>$1</strong>');
    src = src.replace(/__(.+?)__/g, '<strong>$1</strong>');

    // Italic *
    src = src.replace(/\*(.+?)\*/g, '<em>$1</em>');
    src = src.replace(/_(.+?)_/g, '<em>$1</em>');

    // Strikethrough
    src = src.replace(/~~(.+?)~~/g, '<del>$1</del>');

    // Line breaks
    src = src.replace(/  \n/g, '<br>\n');

    // Paragraphs - wrap remaining text in <p>
    var lines = src.split('\n\n');
    for (var i = 0; i < lines.length; i++) {
      var l = lines[i].trim();
      if (l && !/^<(h[1-6]|ul|ol|li|blockquote|pre|hr|div|table)/.test(l) && !/^%%CODEBLOCK/.test(l)) {
        // Check if it's inline content (no block-level tags)
        if (!/^<(p|ul|ol|li|h[1-6]|blockquote|pre|hr|div|table)/.test(l)) {
          lines[i] = '<p>' + l.replace(/\n/g, '<br>') + '</p>';
        }
      }
    }
    src = lines.join('\n\n');

    // Restore code blocks
    src = src.replace(/%%CODEBLOCK(\d+)%%/g, function(m, idx) {
      return codeBlocks[parseInt(idx)] || '';
    });

    // Clean up empty paragraphs
    src = src.replace(/<p>\s*<\/p>/g, '');

    return src;
  }

  function escapeHtml(str) {
    return str.replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;').replace(/"/g, '&quot;');
  }

  if (typeof module !== 'undefined' && module.exports) {
    module.exports = marked;
    marked.default = marked;
  } else {
    window.marked = marked;
  }
})();
